@app.route("/api/trends")
def api_trends():
    """Compute blunder rate per game over time.
    
    - 'games' (optional): original game PGN — used for Stockfish analysis if no puzzles provided
    - 'puzzles' (optional): pre-generated puzzle PGN — fast path, no engine needed
    - At least one must be provided. If puzzle file has GameMoves headers, games file is unnecessary.
    """
    games_file = request.args.get("games", "")
    puzzles_file = request.args.get("puzzles", "")
    player = request.args.get("player", "")

    for f in (games_file, puzzles_file):
        if f and ("/" in f or "\\" in f):
            return jsonify({"error": "Invalid file"}), 400

    puzzles_path = os.path.join(PUZZLE_DIR, puzzles_file) if puzzles_file else None
    games_path = os.path.join(PUZZLE_DIR, games_file) if games_file else None

    if not (games_path and os.path.isfile(games_path or "")) and not (puzzles_path and os.path.isfile(puzzles_path or "")):
        return jsonify({"error": "Provide at least one valid file"}), 400

    # Fast path: use puzzle PGN
    if puzzles_path and os.path.isfile(puzzles_path):
        game_blunders = {}  # key -> {blunders, game_moves, date, game}
        with open(puzzles_path) as f:
            while True:
                g = chess.pgn.read_game(f)
                if g is None:
                    break
                h = g.headers
                turn = h.get("PuzzleTurn", "")
                white, black = h.get("White", "?"), h.get("Black", "?")
                date = h.get("Date", "????.??.??")
                gm = int(h.get("GameMoves", "0"))
                if player:
                    pl = player.lower()
                    if turn == "white" and pl not in white.lower():
                        continue
                    if turn == "black" and pl not in black.lower():
                        continue
                key = f"{white}|{black}|{date}"
                if key not in game_blunders:
                    game_blunders[key] = {"blunders": 0, "game_moves": gm,
                                          "date": date, "game": f"{white} vs {black}"}
                game_blunders[key]["blunders"] += 1
                if gm > game_blunders[key]["game_moves"]:
                    game_blunders[key]["game_moves"] = gm

        # Fill missing move counts from games file if needed
        needs_moves = any(v["game_moves"] == 0 for v in game_blunders.values())
        if needs_moves and games_path and os.path.isfile(games_path):
            with open(games_path) as f:
                while True:
                    g = chess.pgn.read_game(f)
                    if g is None:
                        break
                    h = g.headers
                    key = f"{h.get('White','?')}|{h.get('Black','?')}|{h.get('Date','????.??.??')}"
                    if key in game_blunders and game_blunders[key]["game_moves"] == 0:
                        game_blunders[key]["game_moves"] = sum(1 for _ in g.mainline())

        series = []
        for v in game_blunders.values():
            rate = round(v["blunders"] / v["game_moves"], 4) if v["game_moves"] > 0 else 0
            series.append({"date": v["date"], "game": v["game"],
                          "blunders": v["blunders"], "total_moves": v["game_moves"],
                          "blunder_rate": rate})
        return jsonify(sorted(series, key=lambda x: x["date"]))

    # Slow path: run Stockfish on game PGN
    if not games_path or not os.path.isfile(games_path):
        return jsonify({"error": "Games file not found"}), 404

    from puzzles import download_stockfish, evaluate, score_to_cp
    stockfish_path = download_stockfish()
    engine = chess.engine.SimpleEngine.popen_uci(stockfish_path)
    series = []
    try:
        with open(games_path) as f:
            while True:
                g = chess.pgn.read_game(f)
                if g is None:
                    break
                h = g.headers
                white, black = h.get("White", "?"), h.get("Black", "?")
                if player:
                    pl = player.lower()
                    if pl not in white.lower() and pl not in black.lower():
                        continue
                board = g.board()
                prev_score = evaluate(engine, board, 15)
                blunders = 0
                total_moves = 0
                for node in g.mainline():
                    turn = board.turn
                    board.push(node.move)
                    curr_score = evaluate(engine, board, 15)
                    total_moves += 1
                    drop = (score_to_cp(prev_score) - score_to_cp(curr_score)) if turn == chess.WHITE else (score_to_cp(curr_score) - score_to_cp(prev_score))
                    if drop >= 200:
                        if not player or (player.lower() in (white if turn == chess.WHITE else black).lower()):
                            blunders += 1
                    prev_score = curr_score
                rate = round(blunders / total_moves, 4) if total_moves > 0 else 0
                series.append({"date": h.get("Date", "????.??.??"),
                              "game": f"{white} vs {black}",
                              "blunders": blunders, "total_moves": total_moves,
                              "blunder_rate": rate})
    finally:
        engine.quit()
    return jsonify(series)


