@app.route("/api/db/users/<username>/import", methods=["POST"])
def api_db_import_games(username):
    """Import games from Chess.com into the database for a user."""
    import requests as req
    user = db.get_user(username)
    if not user:
        return jsonify({"error": "User not found"}), 404
    chess_com_user = (request.json or {}).get("chess_com_username") or user["chess_com_username"] or username
    from_date = (request.json or {}).get("from_date", "")
    to_date = (request.json or {}).get("to_date", "")
    headers = {"User-Agent": "FischerChess/1.0"}

    r = req.get(f"https://api.chess.com/pub/player/{chess_com_user}/games/archives", headers=headers)
    if r.status_code != 200:
        return jsonify({"error": f"Chess.com API error: {r.status_code}"}), 400
    archives = r.json().get("archives", [])

    imported = 0
    for url in archives:
        r = req.get(url, headers=headers)
        if r.status_code != 200:
            continue
        for game in r.json().get("games", []):
            pgn_text = game.get("pgn", "")
            if not pgn_text:
                continue
            chess_com_id = game.get("url", "")
            import io
            g = chess.pgn.read_game(io.StringIO(pgn_text))
            if not g:
                continue
            h = g.headers
            game_date = h.get("Date", "").replace(".", "-")
            if from_date and game_date < from_date:
                continue
            if to_date and game_date > to_date:
                continue
            total_moves = sum(1 for _ in g.mainline())
            game_id = db.save_game(
                user["id"], pgn_text, h.get("White", "?"), h.get("Black", "?"),
                h.get("Result", "*"), h.get("Date", ""), h.get("Event", ""),
                total_moves, chess_com_id
            )
            if game_id:
                imported += 1

    return jsonify({"imported": imported, "username": username})


@app.route("/api/db/users/<username>/import-pgn", methods=["POST"])
def api_db_import_pgn(username):
    """Import games from an uploaded PGN file."""
    user = db.get_user(username)
    if not user:
        return jsonify({"error": "User not found"}), 404
    file = request.files.get("file")
    if not file:
        return jsonify({"error": "No file uploaded"}), 400
    import io
    pgn_text_all = file.read().decode("utf-8", errors="ignore")
    stream = io.StringIO(pgn_text_all)
    imported = 0
    while True:
        g = chess.pgn.read_game(stream)
        if g is None:
            break
        h = g.headers
        total_moves = sum(1 for _ in g.mainline())
        pgn_str = str(g)
        game_id = db.save_game(
            user["id"], pgn_str, h.get("White", "?"), h.get("Black", "?"),
            h.get("Result", "*"), h.get("Date", ""), h.get("Event", ""),
            total_moves, None
        )
        if game_id:
            imported += 1
    return jsonify({"imported": imported, "username": username})


