@app.route("/api/db/users/<username>/generate-puzzles", methods=["POST"])
def api_db_generate_puzzles(username):
    """Generate puzzles from user's games in DB and save them."""
    user = db.get_user(username)
    if not user:
        return jsonify({"error": "User not found"}), 404

    from puzzles import download_stockfish, analyze_game, evaluate
    from tactics import classify_tactic
    import chess.engine as ce

    data = request.get_json() or {}
    threshold = data.get("threshold", 200)
    depth = data.get("depth", 15)
    limit = data.get("limit", 50)  # max games to analyze
    player_name = data.get("player_name", "").strip()  # name as it appears in PGN headers

    games = db.get_user_games(user["id"], limit)
    if not games:
        return jsonify({"error": "No games found"}), 404

    stockfish_path = download_stockfish()
    engine = ce.SimpleEngine.popen_uci(stockfish_path)
    engine.configure({"Hash": 64, "Threads": 1})
    total_puzzles = 0

    try:
        for game_row in games:
            import io
            g = chess.pgn.read_game(io.StringIO(game_row["pgn"]))
            if not g:
                continue
            puzzles = analyze_game(engine, g, threshold, depth)
            # Filter to user's blunders only if player_name specified
            filter_name = player_name.lower() if player_name else (user["chess_com_username"] or "").lower()
            for p in puzzles:
                if filter_name:
                    is_user = (p["turn"] == "white" and filter_name in game_row["white"].lower()) or \
                              (p["turn"] == "black" and filter_name in game_row["black"].lower())
                    if not is_user:
                        continue
                db.save_puzzle(
                    user["id"], game_row["id"], p["fen"],
                    p["best_move_uci"], p["best_move"], p["played"],
                    p["reason"], p["drop"], p["move_number"], p["turn"],
                    ",".join(p.get("tactics", [])),
                    ",".join(p.get("acceptable_uci", []))
                )
                total_puzzles += 1
    finally:
        engine.quit()

    return jsonify({"puzzles_generated": total_puzzles, "games_analyzed": len(games)})


